const results = [];
for (const item of $input.all()) {
  const msg = item.json;
  // Try raw Gmail API headers array first
  const headers = msg.payload?.headers || msg.headers || [];
  const getHeader = (name) => {
    const h = headers.find(h => h.name?.toLowerCase() === name.toLowerCase());
    return h ? h.value : '';
  };
  // Fallback to simplified Gmail node fields if headers array isn't present
  const subject = getHeader('Subject') || msg.Subject || msg.subject || '';
  const from = getHeader('From') || msg.From || msg.from || '';
  const internalDateMs = msg.internalDate;
  const dateStamp = internalDateMs
    ? new Date(Number(internalDateMs)).toISOString().split('T')[0]
    : null;
  results.push({
    json: {
      dateStamp: dateStamp,
      snippet: msg.snippet || msg.Snippet || '',
      Subject: subject,
      From: from,
    }
  });
}
return results;

const item = $input.item.json;

// Try every possible key Gemini might use
const raw = 
  item.text ??
  item.output ??
  item.response ??
  item.content ??
  item.message?.content ??
  JSON.stringify(item);

// Convert to string if it's already an object
const rawStr = typeof raw === "object" ? JSON.stringify(raw) : String(raw);

// Strip markdown code fences if present
const stripped = rawStr
  .replace(/```json/gi, "")
  .replace(/```/g, "")
  .trim();

// Extract the first valid JSON object
const match = stripped.match(/\{[\s\S]*\}/);

if (!match) {
  return [{ json: {
    isJobRelated: false,
    company: null,
    role: null,
    status: "N/A",
    dateReceived: null,
    notes: null,
    jobPoster: "N/A",
    parseError: "no JSON object found in: " + rawStr.substring(0, 100)
  }}];
}

let parsed;
try {
  parsed = JSON.parse(match[0].trim());
} catch(e) {
  return [{ json: {
    isJobRelated: false,
    company: null,
    role: null,
    status: "N/A",
    dateReceived: null,
    notes: null,
    jobPoster: "N/A",
    parseError: "JSON.parse failed: " + e.message
  }}];
}

// Normalize isJobRelated to boolean
parsed.isJobRelated = parsed.isJobRelated === true || parsed.isJobRelated === "true";

// Guarantee all fields exist
return [{ json: {
  isJobRelated: parsed.isJobRelated ?? false,
  company: parsed.company ?? null,
  role: parsed.role ?? null,
  status: parsed.status ?? "N/A",
  dateReceived: parsed.dateReceived ?? null,
  notes: parsed.notes ?? null,
  jobPoster: parsed.jobPoster ?? "N/A",
  id: `${parsed.company ?? "unknown"}_${parsed.role ?? "unknown"}`.toLowerCase().replace(/\s+/g, "_")
}}];
